mapper.update:
UPDATE ai_agent
agent_id = #{agentId}, agent_name = #{agentName}, description = #{description}, channel = #{channel}, status = #{status}, update_time = #{updateTime},
WHERE id = #{id}

mapper.select:
SELECT id, agent_id, agent_name, description, channel, status, create_time, update_time
FROM ai_agent
WHERE id = #{id}

SELECT id, agent_id, agent_name, description, channel, status, create_time, update_time
FROM ai_agent
WHERE agent_id = #{agentId}

SELECT id, agent_id, agent_name, description, channel, status, create_time, update_time
FROM ai_agent

    AND agent_id = #{agentId}
    AND agent_name LIKE CONCAT('%', #{agentName}, '%')
    AND channel = #{channel}
    AND status = #{status}

ORDER BY create_time DESC
